class Solution:
    def stoneGameVII(self, stones):
        """
        :type stones: List[int]
        :rtype: int
        """
        n = len(stones)
        memo = {}
        prefix = [0] * (n + 1)

        for i in range(n):
            prefix[i + 1] = prefix[i] + stones[i]

        def dp(i, j):
            if i >= j:
                return 0
            if (i, j) in memo:
                return memo[(i, j)]

            # Remove left or right
            left = prefix[j + 1] - prefix[i + 1] - dp(i + 1, j)
            right = prefix[j] - prefix[i] - dp(i, j - 1)

            result = max(left, right)
            memo[(i, j)] = result
            return result

        return dp(0, n - 1)
